urlset:

  {=site.url.root.url.raw}/
  daily
  1.0

{#for section in cdi:sitemap-links.sections.orEmpty}
  {#for link in section.links.orEmpty}
    {#if !link.external}

  {=site.url.root.url.raw}{=link.url.raw}
  {=link.changefreq ?: 'monthly'}
  {=link.priority ?: '0.5'}

    {/if}
  {/for}
  {#if section.subsections}
    {#for subsection in section.subsections.orEmpty}
      {#for link in subsection.links.orEmpty}
        {#if !link.external}

  {=site.url.root.url.raw}{=link.url.raw}
  {=link.changefreq ?: 'monthly'}
  {=link.priority ?: '0.5'}

        {/if}
      {/for}
    {/for}
  {/if}
{/for}
